INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '1-1', 'Minero, sepulturero, alguien cuyo trabajo estaba relacionado con el subsuelo.', 'Cultivadora de huertos, especialista en remedios, cocinera.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '1-2', 'Filósofo, y explorador de nuevos territorios, mentales o geográficos.', 'Consejera o ama de llaves; persona encargada de instruir a los jóvenes.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '1-3', 'Inventor, que estudiaba varias ciencias al mismo tiempo.', 'Decoradora; diseñadora; modista, especialista en tejidos o ropa.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '1-4', 'Químico, alquimista o tintorero; persona que trabajaba con mezcla de sustancias.', 'Fabricante de perfumes, cosméticos, lociones o ungüentos.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '1-5', 'Carpintero o alguien con habilidad manual para trabajar la madera.', 'Posición de servidumbre; esclava, sirvienta, criada.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '1-6', 'Relojero o profesional relacionado con la medida del tiempo.', 'Encargada de trabajos refinados; joyera, bordadora o tejedora.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '1-7', 'Médico, cirujano, persona especializada en plantas curativas.', 'Sacerdotisa, bruja; que se valía de la religión o de la magia para curar.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '2-1', 'Trabajó la artesanía, los metales, la cerámica de objetos domésticos.', 'Tejedora de tapetes, telas, algodón, lanas; mujer que laboró con hilos.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '2-2', 'Guía del territorio o cartógrafo; astrónomo, astrólogo, adivino.', 'Pitonisa, vidente, adivina. Mujer temida por sus poderes sobrenaturales.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '2-3', 'Constructores de caminos, puertos o puentes; arquitecto o ingeniero.', 'Persona que realiza trabajos pesados, como lavar o planchar.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '2-4', 'Guerrero, mercenario, carnicero, gladiador o verdugo.', 'Aventurera, guerrera, espía, líder feminista.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '2-5', 'Artista solitario y no reconocido por la sociedad; místico.', 'Famosa por su belleza; amante, concubina, cortesana, "modelo", preferida del rey.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '2-6', 'Navegante o constructor de navíos; profesiones relacionadas con el agua.', 'Comerciante, vendedora en el mercado; mujer que cultivaba la tierra.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '2-7', 'Escultor en madera o piedra; constructor de templos o palacios.', 'Persona que laboraba con paja, cuerda o fibras naturales.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '3-1', 'Pastor, caballero, cazador, pescador; actividades relacionadas con animales.', 'Pastora, granjera, mujer que cuida de animales.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '3-2', 'Soldado, jefe militar, líder político, rey o emperador.', 'Emperatriz, reina; mujer de alta posición política o social.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '3-3', 'Abogado, bibliotecario, cronista, historiador o escribano.', 'Enfermera, asistenta social, monja que vivía en Hospitales.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '3-4', 'Actor de teatro, danzarín, poeta, trovador, cantante o músico.', 'Cantante, artista del arpa o la cítara; alguien con actividades afines con la música.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '3-5', 'Comerciante u hombre de negocios, prestamista.', 'Mujer con muchas propiedades, una heredera o viuda de hombre rico.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '3-6', 'Persona solitaria, ermitaño, monje, prisionero o esclavo.', 'Alguien con vida solitaria, abadesa, virgen consagrada a algún dios.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '3-7', 'Maestro de ceremonias, de rituales religiosos o palaciegos; bufón del rey.', 'Embajadora o diplomática; mujer de gran influencia en círculos políticos.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '4-1', 'Profesor o maestro, hechicero o iniciado en ciencias ocultas.', 'Hotelera, tabernera, alguien que cocinaba para muchas personas.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '4-2', 'Escritor o impresor; trovador, contador de historias.', 'Maestra; gran sacerdotisa encargada de rituales y de la instrucción de los iniciados en un culto.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '4-3', 'Ganadero o agricultor; comerciante de lana y cuero; contrabandista.', 'Mujer que trabajaba con cuero en la limpieza, curtiembre o confección de ropas.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '4-4', 'Sacerdote, eunuco, guardián de harén, favorito de un rey o una reina.', 'Bailarina, acróbata, actriz de teatro, de grupo ambulante, prostituta.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '4-5', 'Banquero o jugador; persona que manejaba grandes cantidades de dinero.', 'Mujer que elaboraba dulces, quesos o que vendía esos productos.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '4-6', 'Capitán de barco, pirata, aventurero, conquistador.', 'Persona que realizaba oficios bajos; delatora.');
INSERT INTO profession_lookup(id, code, description_male, description_female) VALUES (null, '4-7', 'Sabio o científico; guía espiritual; papa o cardenal; ministro.', 'Artesana o diseñadora de objetos de cerámica o vidrio. Pintora.');
INSERT INTO personality_lookup(id, simbol_code, simbol_name, description_odd, description_even) VALUES (null, 'AAAA', 'Cuadrado', 'Gracias a su fuerte personalidad y visión positiva de la vida, consiguió liderar con éxito grandes movimientos políticos y sociales.', 'Inquieto y creativo, trató de transformar a toda costa los patrones de comportamiento de la época. Sin duda fue un gran revolucionario.');
INSERT INTO personality_lookup(id, simbol_code, simbol_name, description_odd, description_even) VALUES (null, 'BBBB', 'Círculo dentro de Cuadrado', 'Quien tuvo la oportunidad de conocerlo, vivió momentos de inmensa alegría; toda su vibrante energía fue dirigida en beneficio de sus semejantes.', 'Su pasividad y timidez fueron las culpables de todas las situaciones difíciles que tuvo que enfrentar. Menos mal que su intuición lo guiaba para salir bien de ellas.');
INSERT INTO personality_lookup(id, simbol_code, simbol_name, description_odd, description_even) VALUES (null, 'CCCC', 'Triángulo', 'Con su sed de conocimientos y búsqueda de la verdad, fue un místico bastante respetado. Pocos tenían tanta seguridad de una vida futura como usted.', '¡Qué vida tan agitada! Viajes, aventuras sentimentales, proyectos repentinos: con todo eso no tuvo tiempo para lamentar las pequeñas pérdidas de la rutina diaria.');
INSERT INTO personality_lookup(id, simbol_code, simbol_name, description_odd, description_even) VALUES (null, 'DDDD', 'Reloj de Arena', 'A pesar de tener una excelente intuición, fue muy práctico en sus decisiones. Bondadoso y honesto, realizó importantes obras sociales y protegió a los débiles y oprimidos.', 'Seguro y determinado, siempre quiso que los otros siguieran sus ideas, y hasta irracionales.');
INSERT INTO personality_lookup(id, simbol_code, simbol_name, description_odd, description_even) VALUES (null, 'EEEE', 'Icono de Persona', 'Llegó casi a la genialidad. Su capacidad de penetrar la mente y el corazón de las personas más complicadas lo convirtió en un ser amado y temido por todos.', 'Con su mente privilegiada, calma y justicia, probablemente ocupó altos cargos sin jamás imponer cualquier tipo de humillación a sus subalternos.');
INSERT INTO personality_lookup(id, simbol_code, simbol_name, description_odd, description_even) VALUES (null, 'FFFF', 'Círculo', 'Con su especial inteligencia y múltiples talentos, tuvo una vida relativamente tranquila y conquistó altas posiciones en el trabajo.', 'Innovador, posiblemente se destacó en actividades relacionadas con la música, la danza o la artesanía. Recibió muchas críticas antes de que reconocieran su talento.');
INSERT INTO personality_lookup(id, simbol_code, simbol_name, description_odd, description_even) VALUES (null, 'GGGG', 'Círculo dentro de Doble Cuadrado', 'No fue fácil imponer sus ideas en una sociedad cerrada a todo lo que era nuevo. Sin embargo, al final de su vida, su inteligencia y lucidez fueron reconocidas.', 'Capaz de controlarlo todo y a todos, su gran objetivo fue alcanzar puestos de mando. Dominante, fuerte y atrayente, fue siempre muy admirado hasta por sus enemigos.');
